// Input: single item from ConnectSafely "Get Profile" response

const item = items[0].json;

const profile = item.profile || {};

const profileUrn = profile.entityUrn || null;
const profileId = item.profileId || profile.publicIdentifier || null;
const publicIdentifier = profile.publicIdentifier || null;

const firstName = profile.firstName || null;
const lastName = profile.lastName || null;

const profileUrl = publicIdentifier
  ? `https://www.linkedin.com/in/${publicIdentifier}/`
  : null;

return [
  {
    json: {
      success: item.success ?? false,

      // Core identifiers (MOST IMPORTANT)
      profileUrn,
      profileId,
      publicIdentifier,
      profileUrl,

      // Optional enrichment
      firstName,
      lastName,
      headline: profile.headline || null,
      countryCode: profile.location?.countryCode || null,
    },
  },
];
